 1	import * as React from 'react';
 2	import { PoolType } from '@odf/ocs/constants';
 3	import { OverviewDetailItem as DetailItem } from '@odf/shared/overview-page';
 4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 5	import {
 6	  Card,
 7	  CardBody,
 8	  CardHeader,
 9	  CardTitle,
10	  DescriptionList,
11	} from '@patternfly/react-core';
12	import { BlockPoolDashboardContext } from './block-pool-dashboard-context';
13	
14	export const DetailsCard: React.FC = () => {
15	  const { t } = useCustomTranslation();
16	  const { obj } = React.useContext(BlockPoolDashboardContext);
17	  const volumeType = PoolType.BLOCK;
18	  const deviceType = obj.spec?.deviceClass?.toUpperCase() ?? '-';
19	
20	  return (
21	    <Card data-test-id="details-card">
22	      <CardHeader>
23	        <CardTitle>{t('Details')}</CardTitle>
24	      </CardHeader>
25	      <CardBody>
26	        <DescriptionList>
27	          <DetailItem isLoading={!obj} title={t('Pool name')}>
28	            {obj.metadata?.name}
29	          </DetailItem>
30	          <DetailItem isLoading={!obj} title={t('Volume type')}>
31	            {volumeType}
32	          </DetailItem>
33	          <DetailItem isLoading={!obj} title={t('Device type')}>
34	            {deviceType}
35	          </DetailItem>
36	          <DetailItem isLoading={!obj} title={t('Replicas')}>
37	            {obj.spec?.replicated?.size}
38	          </DetailItem>
39	        </DescriptionList>
40	      </CardBody>
41	    </Card>
42	  );
43	};

